-- ==============================================================
-- 03_seed_events.sql  (라이브 DB 검증 스냅샷, 2026-05-31 추출)
-- 실제 학회 사이트(KAOMT·IAPNFK·KBA·KACRPT·KSPNF) 기준 검증 데이터.
-- 접수기간(apply_*) / 교육기간(edu_*) 포함. status 는 뷰에서 동적 계산되므로
-- 여기 값은 초기값일 뿐(런타임 표시는 current_date 기준).
-- 실행 순서: 01_schema → 02_seed_organizations → 03_seed_events
-- ==============================================================


ON CONFLICT (org_id, external_id, start_date) DO NOTHING;

-- 검증
DO $$
DECLARE cnt int;
BEGIN
  SELECT count(*) INTO cnt FROM public.events;
  RAISE NOTICE '✓ 일정 % 건 등록 완료', cnt;
END $$;
